import React, { useEffect, useMemo, useState } from "react";
import "./App.css";

const fallbackImages = [
  "https://images.unsplash.com/photo-1600891964599-f61ba0e24092?auto=format&fit=crop&w=1200&q=80",
  "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=1200&q=80",
  "https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?auto=format&fit=crop&w=1200&q=80",
  "https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=1200&q=80"
];

const ratingMap = {
  Frankie: 4.4,
  Maggie: 4.2,
  Sandwich: 4.3,
  Burger: 4.5,
  Pizza: 4.6,
  Meals: 4.1,
  Parota: 4.0,
  Rice: 4.3,
  Biryani: 4.8
};

const foodImageMap = {
  "Veg Frankie 🌯": "https://images.unsplash.com/photo-1626700051175-6818013e1d4f?auto=format&fit=crop&w=900&q=80",
  "Egg Frankie 🥚🌯": "https://images.unsplash.com/photo-1626700051175-6818013e1d4f?auto=format&fit=crop&w=900&q=80",
  "Chicken Frankie 🍗🌯": "https://images.unsplash.com/photo-1626700051175-6818013e1d4f?auto=format&fit=crop&w=900&q=80",
  "Veg Maggie 🍜": "https://images.unsplash.com/photo-1612929633738-8fe44f7ec841?auto=format&fit=crop&w=900&q=80",
  "Egg Maggie 🥚🍜": "https://images.unsplash.com/photo-1612929633738-8fe44f7ec841?auto=format&fit=crop&w=900&q=80",
  "Chicken Maggie 🍗🍜": "https://images.unsplash.com/photo-1612929633738-8fe44f7ec841?auto=format&fit=crop&w=900&q=80",
  "Veg Sandwich 🥪": "https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=900&q=80",
  "Egg Sandwich 🥚🥪": "https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=900&q=80",
  "Chicken Sandwich 🍗🥪": "https://images.unsplash.com/photo-1528735602780-2552fd46c7af?auto=format&fit=crop&w=900&q=80",
  "Veg Burger 🍔": "https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=900&q=80",
  "Chicken Burger 🍗🍔": "https://images.unsplash.com/photo-1568901346375-23c9450c58cd?auto=format&fit=crop&w=900&q=80",
  "Veg Pizza 🍕": "https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=900&q=80",
  "Chicken Pizza 🍗🍕": "https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=900&q=80",
  "Veg Meals 🍱": "https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=900&q=80",
  "Veg Parota 🫓": "https://images.unsplash.com/photo-1631452180519-c014fe946bc7?auto=format&fit=crop&w=900&q=80",
  "Veg Fried Rice 🍚": "https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=900&q=80",
  "Egg Fried Rice 🥚🍚": "https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=900&q=80",
  "Chicken Fried Rice 🍗🍚": "https://images.unsplash.com/photo-1512058564366-18510be2db19?auto=format&fit=crop&w=900&q=80",
  "Veg Biryani 🍛": "https://images.unsplash.com/photo-1633945274405-b6c5e8f4d1a5?auto=format&fit=crop&w=900&q=80",
  "Chicken Biryani 🍗🍛": "https://images.unsplash.com/photo-1633945274405-b6c5e8f4d1a5?auto=format&fit=crop&w=900&q=80"
};

function LoaderCards() {
  return (
    <div className="menu-grid">
      {[1, 2, 3, 4].map((x) => (
        <div className="menu-card shimmer-card" key={x}>
          <div className="shimmer-image" />
          <div className="menu-card-body">
            <div className="shimmer-line lg" />
            <div className="shimmer-line md" />
            <div className="shimmer-line sm" />
          </div>
        </div>
      ))}
    </div>
  );
}

function App() {
  const [foods, setFoods] = useState([]);
  const [orders, setOrders] = useState([]);
  const [page, setPage] = useState("menu");
  const [category, setCategory] = useState("All");
  const [search, setSearch] = useState("");
  const [cart, setCart] = useState([]);
  const [paymentMode, setPaymentMode] = useState("UPI");
  const [orderType, setOrderType] = useState("Takeaway");
  const [notes, setNotes] = useState("");
  const [paymentState, setPaymentState] = useState("idle");
  const [message, setMessage] = useState("");
  const [bgIndex, setBgIndex] = useState(0);
  const [showCheckout, setShowCheckout] = useState(false);
  const [loadingFoods, setLoadingFoods] = useState(true);
  const [loadingOrders, setLoadingOrders] = useState(true);

  useEffect(() => {
    loadFoods();
    loadOrders();
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      setBgIndex((prev) => (prev + 1) % fallbackImages.length);
    }, 4000);
    return () => clearInterval(timer);
  }, []);

  const loadFoods = async () => {
    setLoadingFoods(true);
    try {
      const res = await fetch("http://localhost:8080/foods");
      const data = await res.json();
      setFoods(Array.isArray(data) ? data : []);
    } catch {
      setMessage("Could not load foods");
    } finally {
      setLoadingFoods(false);
    }
  };

  const loadOrders = async () => {
    setLoadingOrders(true);
    try {
      const res = await fetch("http://localhost:8080/orders");
      const data = await res.json();
      setOrders(Array.isArray(data) ? data : []);
    } catch {
      setMessage("Could not load orders");
    } finally {
      setLoadingOrders(false);
    }
  };

  const categories = useMemo(() => {
    return ["All", ...new Set(foods.map((item) => item.category))];
  }, [foods]);

  const foodsWithMeta = useMemo(() => {
    return foods.map((food, index) => ({
      ...food,
      rating: ratingMap[food.category] || 4.2,
      imageUrlResolved:
        foodImageMap[food.name] ||
        food.imageUrl ||
        fallbackImages[index % fallbackImages.length]
    }));
  }, [foods]);

  const filteredFoods = useMemo(() => {
    return foodsWithMeta.filter((food) => {
      const catOk = category === "All" || food.category === category;
      const searchOk = food.name.toLowerCase().includes(search.toLowerCase());
      return catOk && searchOk;
    });
  }, [foodsWithMeta, category, search]);

  const popularFoods = useMemo(() => {
    const popularNames = [
      "Chicken Biryani 🍗🍛",
      "Veg Pizza 🍕",
      "Chicken Pizza 🍗🍕",
      "Chicken Burger 🍗🍔",
      "Veg Frankie 🌯",
      "Chicken Fried Rice 🍗🍚"
    ];
    const curated = foodsWithMeta.filter((food) => popularNames.includes(food.name));
    return curated.length ? curated : foodsWithMeta.slice(0, 6);
  }, [foodsWithMeta]);

  const addToCart = (food) => {
    setMessage("");
    setCart((prev) => {
      const existing = prev.find((item) => item.id === food.id);
      if (existing) {
        return prev.map((item) =>
          item.id === food.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...food, quantity: 1 }];
    });
  };

  const updateCartQty = (id, delta) => {
    setCart((prev) =>
      prev
        .map((item) =>
          item.id === id ? { ...item, quantity: Math.max(0, item.quantity + delta) } : item
        )
        .filter((item) => item.quantity > 0)
    );
  };

  const removeFromCart = (id) => {
    setCart((prev) => prev.filter((item) => item.id !== id));
  };

  const subtotal = useMemo(() => {
    return cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
  }, [cart]);

  const totalItems = useMemo(() => {
    return cart.reduce((sum, item) => sum + item.quantity, 0);
  }, [cart]);

  const handlingFee = cart.length ? 10 : 0;
  const gst = Math.round(subtotal * 0.05);
  const total = subtotal + handlingFee + gst;
  const waitingTime = 10 + totalItems * 3;

  const placeCartOrder = async () => {
    if (cart.length === 0) {
      setMessage("Add items to cart first");
      return;
    }

    setPaymentState("processing");
    setMessage("");

    try {
      for (const item of cart) {
        await fetch("http://localhost:8080/orders", {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            foodName: `${item.name} | ${orderType} | ${paymentMode}${notes ? " | Note: " + notes : ""}`,
            quantity: Number(item.quantity),
            totalPrice: item.price * Number(item.quantity),
            status: "Pending"
          })
        });
      }

      setPaymentState("success");
      setMessage(`Order placed successfully. Estimated waiting time: ${waitingTime} mins`);
      setCart([]);
      setNotes("");
      setPaymentMode("UPI");
      setOrderType("Takeaway");
      setShowCheckout(false);
      await loadOrders();
      setPage("orders");
    } catch {
      setPaymentState("failed");
      setMessage("Failed to place order");
    }
  };

  const updateOrderStatus = async (order, newStatus) => {
    const response = await fetch(`http://localhost:8080/orders/${order.id}`, {
      method: "PUT",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        foodName: order.foodName,
        quantity: order.quantity,
        totalPrice: order.totalPrice,
        status: newStatus
      })
    });

    if (response.ok) {
      loadOrders();
      setMessage("Order status updated");
    } else {
      setMessage("Failed to update order");
    }
  };

  const analytics = useMemo(() => {
    const totalRevenue = orders.reduce((sum, o) => sum + (o.totalPrice || 0), 0);
    const completedOrders = orders.filter((o) => o.status === "Completed").length;
    const pendingOrders = orders.filter((o) => o.status === "Pending").length;
    const cancelledOrders = orders.filter((o) => o.status === "Cancelled").length;

    const itemCounts = {};
    orders.forEach((o) => {
      const cleanName = o.foodName?.split(" | ")[0] || o.foodName;
      itemCounts[cleanName] = (itemCounts[cleanName] || 0) + (o.quantity || 0);
    });

    const topItems = Object.entries(itemCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5);

    return {
      totalRevenue,
      completedOrders,
      pendingOrders,
      cancelledOrders,
      topItems
    };
  }, [orders]);

  return (
    <div className="app-shell">
      <div
        className="background-slider"
        style={{ backgroundImage: `url("${fallbackImages[bgIndex]}")` }}
      />

      <header className="hero-banner hero-slide">
        <div>
          <h1>🍽️ College Canteen Restaurant</h1>
          <p>Fresh meals, fast ordering, beautiful menu experience.</p>
        </div>
      </header>

      <nav className="top-nav">
        <button className={page === "menu" ? "active nav-btn" : "nav-btn"} onClick={() => setPage("menu")}>
          📋 Menu
        </button>
        <button className={page === "orders" ? "active nav-btn" : "nav-btn"} onClick={() => setPage("orders")}>
          🧾 Orders
        </button>
        <button className={page === "admin" ? "active nav-btn" : "nav-btn"} onClick={() => setPage("admin")}>
          📊 Dashboard
        </button>

        <button className="cart-badge-btn" onClick={() => setShowCheckout(true)}>
          🛒 Cart
          {totalItems > 0 && <span className="cart-badge-count">{totalItems}</span>}
        </button>
      </nav>

      <main className="content-card">
        {page === "menu" && (
          <>
            <section className="section-header">
              <div>
                <h2>🔥 Popular Picks</h2>
                <p className="muted-text">Trending dishes your campus loves most.</p>
              </div>
            </section>

            {loadingFoods ? (
              <LoaderCards />
            ) : (
              <div className="popular-row">
                {popularFoods.map((food) => (
                  <div className="popular-card glow-card" key={`popular-${food.id}`}>
                    <img src={food.imageUrlResolved} alt={food.name} className="food-image small" />
                    <div className="popular-card-body">
                      <h4>{food.name}</h4>
                      <p>{food.category}</p>
                      <strong>₹{food.price}</strong>
                    </div>
                  </div>
                ))}
              </div>
            )}

            <section className="section-header">
              <div>
                <h2>🍔 Explore Menu</h2>
                <p className="muted-text">Search food, filter categories, and add items to cart.</p>
              </div>
            </section>

            <div className="toolbar">
              <input
                className="search-input"
                placeholder="Search food items..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />

              <div className="filter-row">
                {categories.map((cat) => (
                  <button
                    key={cat}
                    className={category === cat ? "chip active-chip" : "chip"}
                    onClick={() => setCategory(cat)}
                  >
                    {cat}
                  </button>
                ))}
              </div>
            </div>

            {loadingFoods ? (
              <LoaderCards />
            ) : (
              <div className="menu-grid">
                {filteredFoods.map((food) => (
                  <div className="menu-card glow-card hover-card" key={food.id}>
                    <img src={food.imageUrlResolved} alt={food.name} className="food-image compact-image" />
                    <div className="menu-card-body">
                      <span className="food-category-tag">{food.category}</span>
                      <h3>{food.name}</h3>
                      <p className="rating-line">
                        <span className="stars">★★★★★</span>
                        <span>{food.rating.toFixed(1)}</span>
                      </p>
                      <p className="price">₹{food.price}</p>
                      <button className="primary-btn" onClick={() => addToCart(food)}>
                        Add to Cart
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            <section className="cart-section">
              <div className="section-header">
                <div>
                  <h2>🛒 Order Cart</h2>
                  <p className="muted-text">Review items, waiting time, and continue to checkout.</p>
                </div>
              </div>

              <div className="cart-layout">
                <div className="cart-card">
                  {cart.length === 0 ? (
                    <p>No items in cart.</p>
                  ) : (
                    cart.map((item) => (
                      <div className="cart-item" key={item.id}>
                        <div>
                          <strong>{item.name}</strong>
                          <p>₹{item.price} each</p>
                        </div>

                        <div className="qty-box">
                          <button onClick={() => updateCartQty(item.id, -1)}>-</button>
                          <span>{item.quantity}</span>
                          <button onClick={() => updateCartQty(item.id, 1)}>+</button>
                          <button className="danger-btn" onClick={() => removeFromCart(item.id)}>
                            Remove
                          </button>
                        </div>
                      </div>
                    ))
                  )}
                </div>

                <div className="payment-card">
                  <h3>💳 Bill Summary</h3>
                  <p className="muted-text">Transparent order summary before payment.</p>

                  <div className="payment-summary">
                    <p><span>Items</span><strong>{totalItems}</strong></p>
                    <p><span>Subtotal</span><strong>₹{subtotal}</strong></p>
                    <p><span>Handling Fee</span><strong>₹{handlingFee}</strong></p>
                    <p><span>GST</span><strong>₹{gst}</strong></p>
                    <p><span>Waiting Time</span><strong>{waitingTime} mins</strong></p>
                    <p className="total-line"><span>Total</span><strong>₹{total}</strong></p>
                  </div>

                  <button className="primary-btn large-btn" onClick={() => setShowCheckout(true)}>
                    Proceed to Checkout
                  </button>

                  {message && <p className="message-text">{message}</p>}
                </div>
              </div>
            </section>
          </>
        )}

        {page === "orders" && (
          <>
            <section className="section-header">
              <div>
                <h2>📦 Orders</h2>
                <p className="muted-text">Track all placed orders and update their status.</p>
              </div>
            </section>

            {loadingOrders ? (
              <LoaderCards />
            ) : (
              <div className="menu-grid">
                {orders.map((order) => (
                  <div className="menu-card glow-card" key={order.id}>
                    <div className="menu-card-body">
                      <h3>{order.foodName}</h3>
                      <p><strong>Qty:</strong> {order.quantity}</p>
                      <p><strong>Total:</strong> ₹{order.totalPrice}</p>
                      <p><strong>Status:</strong> {order.status}</p>
                      <div className="action-row">
                        <button onClick={() => updateOrderStatus(order, "Pending")}>Pending</button>
                        <button onClick={() => updateOrderStatus(order, "Completed")}>Completed</button>
                        <button className="danger-btn" onClick={() => updateOrderStatus(order, "Cancelled")}>
                          Cancelled
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {page === "admin" && (
          <>
            <section className="section-header">
              <div>
                <h2>📊 Admin Dashboard</h2>
                <p className="muted-text">Monitor revenue, order flow, and top-selling items.</p>
              </div>
            </section>

            <div className="analytics-grid">
              <div className="stat-card glow-card">
                <h4>Total Revenue</h4>
                <p>₹{analytics.totalRevenue}</p>
              </div>
              <div className="stat-card glow-card">
                <h4>Completed Orders</h4>
                <p>{analytics.completedOrders}</p>
              </div>
              <div className="stat-card glow-card">
                <h4>Pending Orders</h4>
                <p>{analytics.pendingOrders}</p>
              </div>
              <div className="stat-card glow-card">
                <h4>Cancelled Orders</h4>
                <p>{analytics.cancelledOrders}</p>
              </div>
            </div>

            <div className="top-items-card glow-card">
              <h3>Top Ordered Items</h3>
              {analytics.topItems.length === 0 ? (
                <p>No analytics yet.</p>
              ) : (
                analytics.topItems.map(([name, qty]) => (
                  <div className="top-item-row" key={name}>
                    <span>{name}</span>
                    <strong>{qty}</strong>
                  </div>
                ))
              )}
            </div>
          </>
        )}
      </main>

      {showCheckout && (
        <div className="modal-overlay" onClick={() => setShowCheckout(false)}>
          <div className="checkout-modal glow-card" onClick={(e) => e.stopPropagation()}>
            <h2>Checkout</h2>
            <p className="muted-text">Choose payment method and confirm your order.</p>

            <div className="checkout-grid">
              <div>
                <label>Payment Method</label>
                <select value={paymentMode} onChange={(e) => setPaymentMode(e.target.value)}>
                  <option>UPI</option>
                  <option>Cash on Pickup</option>
                  <option>Card</option>
                </select>
              </div>

              <div>
                <label>Order Type</label>
                <select value={orderType} onChange={(e) => setOrderType(e.target.value)}>
                  <option>Takeaway</option>
                  <option>Dine In</option>
                </select>
              </div>
            </div>

            <div className="checkout-note">
              <label>Special Instructions</label>
              <textarea
                rows="3"
                placeholder="Less spicy, extra sauce, no onion..."
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
              />
            </div>

            <div className="summary-box">
              <p><span>Total Items</span><strong>{totalItems}</strong></p>
              <p><span>Estimated Waiting</span><strong>{waitingTime} mins</strong></p>
              <p><span>Final Amount</span><strong>₹{total}</strong></p>
            </div>

            <div className="payment-method-row">
              <span className={paymentMode === "UPI" ? "pay-chip active-pay" : "pay-chip"}>UPI</span>
              <span className={paymentMode === "Cash on Pickup" ? "pay-chip active-pay" : "pay-chip"}>Cash</span>
              <span className={paymentMode === "Card" ? "pay-chip active-pay" : "pay-chip"}>Card</span>
            </div>

            <div className="modal-actions">
              <button className="secondary-btn" onClick={() => setShowCheckout(false)}>
                Cancel
              </button>
              <button className="primary-btn" onClick={placeCartOrder} disabled={paymentState === "processing"}>
                {paymentState === "processing" ? "Placing..." : "Confirm & Pay"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
